/**
 * @suppress
 */
public object FfiConverterTypeCatalogService: FfiConverter<CatalogService, Long> {
    override fun lower(value: CatalogService): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): CatalogService {
        return CatalogService(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): CatalogService {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: CatalogService) = 8UL

    override fun write(value: CatalogService, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}


