/**
 * The stable, code-and-data error surface the shells receive across the FFI.
 */
sealed class ApiException: kotlin.Exception() {
    
    /**
     * The source's server could not be reached.
     */
    class NetworkUnreachable(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * A request took too long.
     */
    class Timeout(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * The source rejected the supplied credentials.
     */
    class Unauthorized(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * The requested item no longer exists at the source.
     */
    class NotFound(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * Input provided by the user was not usable.
     */
    class InvalidInput(
        
        val `field`: InputField, 
        
        val `issue`: InputIssue
        ) : ApiException() {
        override val message
            get() = "field=${ `field` }, issue=${ `issue` }"
    }
    
    /**
     * The response was fetched but yielded no usable channels.
     */
    class ParseFailed(
        
        /**
         * Channels successfully read.
         */
        val `emitted`: kotlin.ULong, 
        
        /**
         * Entries skipped as malformed.
         */
        val `skipped`: kotlin.ULong
        ) : ApiException() {
        override val message
            get() = "emitted=${ `emitted` }, skipped=${ `skipped` }"
    }
    
    /**
     * The local database could not be read or written.
     */
    class StorageCorrupt(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * The operation was cancelled (by the user or a departing screen).
     */
    class Cancelled(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * An unexpected internal error; the detail is in the log stream.
     */
    class Internal(
        ) : ApiException() {
        override val message
            get() = ""
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<ApiException> {
        override fun lift(error_buf: RustBuffer.ByValue): ApiException = FfiConverterTypeApiError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeApiError : FfiConverterRustBuffer<ApiException> {
    override fun read(buf: ByteBuffer): ApiException {
        

        return when(buf.getInt()) {
            1 -> ApiException.NetworkUnreachable()
            2 -> ApiException.Timeout()
            3 -> ApiException.Unauthorized()
            4 -> ApiException.NotFound()
            5 -> ApiException.InvalidInput(
                FfiConverterTypeInputField.read(buf),
                FfiConverterTypeInputIssue.read(buf),
                )
            6 -> ApiException.ParseFailed(
                FfiConverterULong.read(buf),
                FfiConverterULong.read(buf),
                )
            7 -> ApiException.StorageCorrupt()
            8 -> ApiException.Cancelled()
            9 -> ApiException.Internal()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: ApiException): ULong {
        return when(value) {
            is ApiException.NetworkUnreachable -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.Timeout -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.Unauthorized -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.NotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.InvalidInput -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterTypeInputField.allocationSize(value.`field`)
                + FfiConverterTypeInputIssue.allocationSize(value.`issue`)
            )
            is ApiException.ParseFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterULong.allocationSize(value.`emitted`)
                + FfiConverterULong.allocationSize(value.`skipped`)
            )
            is ApiException.StorageCorrupt -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.Cancelled -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.Internal -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: ApiException, buf: ByteBuffer) {
        when(value) {
            is ApiException.NetworkUnreachable -> {
                buf.putInt(1)
                Unit
            }
            is ApiException.Timeout -> {
                buf.putInt(2)
                Unit
            }
            is ApiException.Unauthorized -> {
                buf.putInt(3)
                Unit
            }
            is ApiException.NotFound -> {
                buf.putInt(4)
                Unit
            }
            is ApiException.InvalidInput -> {
                buf.putInt(5)
                FfiConverterTypeInputField.write(value.`field`, buf)
                FfiConverterTypeInputIssue.write(value.`issue`, buf)
                Unit
            }
            is ApiException.ParseFailed -> {
                buf.putInt(6)
                FfiConverterULong.write(value.`emitted`, buf)
                FfiConverterULong.write(value.`skipped`, buf)
                Unit
            }
            is ApiException.StorageCorrupt -> {
                buf.putInt(7)
                Unit
            }
            is ApiException.Cancelled -> {
                buf.putInt(8)
                Unit
            }
            is ApiException.Internal -> {
                buf.putInt(9)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



/**
 * How much latency the viewer trades for resilience, mapped to engine parameters by each shell
 * (PRD §6.9).
 *
 * The variants mirror `PlayerContract.BufferingProfile` / `player-contract`'s
 * `BufferingProfile` exactly, including their stored spellings. That vocabulary was settled in
 * Phase 5 and is the engine-neutral one both shells already speak — its own docs say "the
 * settings screen speaks this vocabulary" — so the core adopts it rather than inventing a
 * second, lossy one. PRD §6.9's "low-latency vs. stable" is a summary of the axis, not a
 * statement that it has two positions; `Balanced` is the middle the shells default to, and a
 * two-variant core enum would have had no honest value to map it onto.
 */

enum class BufferingProfile {
    
    /**
     * Smallest buffer: fastest zap, least tolerant of a jittery source.
     */
    LOW,
    /**
     * The default trade-off.
     */
    BALANCED,
    /**
     * Largest buffer: slowest to start, rides out a bad connection.
     */
    GENEROUS;

    


    companion object
}


/**
 * @suppress
 */
public object FfiConverterTypeBufferingProfile: FfiConverterRustBuffer<BufferingProfile> {
    override fun read(buf: ByteBuffer) = try {
        BufferingProfile.values()[buf.getInt() - 1]
    } catch (e: IndexOutOfBoundsException) {
        throw RuntimeException("invalid enum value, something is very wrong!!", e)
    }

    override fun allocationSize(value: BufferingProfile) = 4UL

    override fun write(value: BufferingProfile, buf: ByteBuffer) {
        buf.putInt(value.ordinal + 1)
    }
}





